-- ML-Generated Product Aliases
CREATE TABLE IF NOT EXISTS product_aliases (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), alias_name TEXT NOT NULL, canonical_name TEXT NOT NULL, similarity_score NUMERIC, created_at TIMESTAMPTZ DEFAULT NOW()); ALTER TABLE product_aliases ENABLE ROW LEVEL SECURITY; CREATE POLICY "Allow read" ON product_aliases FOR SELECT USING (true); CREATE POLICY "Allow insert" ON product_aliases FOR INSERT WITH CHECK (true);

